export type WasmClientConfig = {
  apiKey: string
  apiBaseUrl?: string
}

export type WasmClientLike = {
  [K in WasmClientMethod]: (argsJson: string) => Promise<string>
}

type WasmClientConstructor = new (apiKey: string, apiBaseUrl?: string | null) => WasmClientLike

/**
 * Shape of the loaded `@solvapay/server-wasm` runtime wrapper (edge profile).
 *
 * `ready()` async-instantiates the module; `ensureReadySync()` synchronously
 * instantiates it (Node `readFileSync`+`initSync`, workerd bundled module,
 * Deno `readFileSync`). Sync envelope methods require one of the two to have
 * completed.
 */
export type WasmBinding = {
  ready: () => Promise<void>
  ensureReadySync?: () => void
  verifyWebhook: (body: string, signature: string, secret: string, nowUnixSecs: number) => string
  WasmClient?: WasmClientConstructor
} & Partial<Record<WasmSyncMethod, (argsJson: string) => string>>

type EnvelopeOk = { ok: true; value: unknown }
type EnvelopeErr = {
  ok: false
  error: {
    kind: string
    message: string
    status?: number | null
    code?: string | null
    gate?: unknown
    retryable?: boolean
  }
}
type Envelope = EnvelopeOk | EnvelopeErr

/** `undefined` = not attempted; Promise caches in-flight / completed async init. */
let initPromise: Promise<WasmBinding> | undefined

/**
 * Synchronously-available binding, set once {@link loadWasmBinding} resolves (or
 * a test override is installed). Required by {@link callWasmSync}.
 */
let syncBinding: WasmBinding | undefined

/**
 * When set (unit tests), skips dynamic import — vitest mocks are unreliable
 * across generated WASM loaders. `null` forces a load failure.
 */
let bindingOverride: WasmBinding | null | undefined

/** Injected fake client for unit tests (`undefined` = construct from binding). */
let clientOverride: WasmClientLike | null | undefined

/** Cache of real `WasmClient` instances keyed by config. */
const clientCache = new Map<string, WasmClientLike>()

function configKey(config: WasmClientConfig): string {
  return `${config.apiKey}\0${config.apiBaseUrl ?? ''}`
}

/**
 * Clears cached WASM init + client state. Used by unit tests.
 * @internal
 */
export function resetWasmCache(): void {
  initPromise = undefined
  syncBinding = undefined
  bindingOverride = undefined
  clientOverride = undefined
  clientCache.clear()
}

/**
 * Injects a fake WASM binding for unit tests (also serves the sync path).
 * @internal
 */
export function setWasmBindingForTests(binding: WasmBinding | null): void {
  bindingOverride = binding
  syncBinding = binding ?? undefined
  initPromise = undefined
  clientCache.clear()
}

/**
 * Injects a fake `WasmClient` for unit tests (skips constructor).
 * @internal
 */
export function setWasmClientForTests(client: WasmClientLike | null): void {
  clientOverride = client
  clientCache.clear()
}

/**
 * True when a fake `WasmClient` override is installed — lets `dispatchClient`
 * force the WASM path under Node vitest (which is otherwise detected as Node).
 * @internal
 */
export function isWasmClientOverrideActive(): boolean {
  return clientOverride !== undefined && clientOverride !== null
}

/** Builds a {@link WasmBinding} facade over the loaded runtime-wrapper module. */
function toBinding(mod: Record<string, unknown>): WasmBinding {
  const binding = mod as unknown as WasmBinding
  return binding
}

/**
 * Loads `@solvapay/server-wasm` once (async), instantiating the module via
 * `ready()`, and caches it for both async and sync dispatch.
 */
export function loadWasmBinding(): Promise<WasmBinding> {
  if (bindingOverride !== undefined) {
    if (bindingOverride === null) {
      return Promise.reject(
        new SolvaPayError('SolvaPay WASM binding (@solvapay/server-wasm) is not available', {
          code: 'internal_error',
        }),
      )
    }
    syncBinding = bindingOverride
    return Promise.resolve(bindingOverride)
  }

  if (!initPromise) {
    initPromise = import('@solvapay/server-wasm')
      .then(async mod => {
        const binding = toBinding(mod as unknown as Record<string, unknown>)
        await binding.ready()
        syncBinding = binding
        return binding
      })
      .catch(err => {
        initPromise = undefined
        if (err instanceof SolvaPayError) throw err
        throw new SolvaPayError(
          err instanceof Error
            ? err.message
            : 'SolvaPay WASM binding (@solvapay/server-wasm) failed to initialize',
          { code: 'internal_error' },
        )
      })
  }
  return initPromise
}

/**
 * Ensures the WASM module is synchronously instantiated so {@link callWasmSync}
 * can run. Requires either a prior awaited {@link loadWasmBinding}/warm-up or a
 * test override — the edge entry warms the module before installing the sync
 * decision / core / MCP APIs.
 *
 * @throws {@link SolvaPayError} when the module has not been warmed up.
 */
export function ensureWasmReadySync(): WasmBinding {
  if (syncBinding !== undefined) {
    try {
      syncBinding.ensureReadySync?.()
    } catch (err) {
      throw new SolvaPayError(
        err instanceof Error
          ? err.message
          : 'SolvaPay WASM binding failed synchronous initialization',
        { code: 'internal_error' },
      )
    }
    return syncBinding
  }

  throw new SolvaPayError(
    'SolvaPay WASM binding (@solvapay/server-wasm) is not ready; await ready() before sync use',
    { code: 'internal_error' },
  )
}

/**
 * Returns a cached WASM `WasmClient` for the given config.
 *
 * Requires a prior awaited {@link loadWasmBinding} (or a test override) so the
 * binding + constructor are available synchronously.
 */
export function getWasmClient(config: WasmClientConfig): WasmClientLike {
  if (clientOverride !== undefined && clientOverride !== null) {
    return clientOverride
  }
  if (clientOverride === null) {
    throw new SolvaPayError('SolvaPay WASM binding (@solvapay/server-wasm) is not available', {
      code: 'internal_error',
    })
  }

  const key = configKey(config)
  const cached = clientCache.get(key)
  if (cached) return cached

  const binding = syncBinding
  if (binding === undefined || binding.WasmClient === undefined) {
    throw new SolvaPayError(
      'SolvaPay WASM binding (@solvapay/server-wasm) is not ready; await ready() first',
      { code: 'internal_error' },
    )
  }

  const client = new binding.WasmClient(config.apiKey, config.apiBaseUrl ?? null)
  clientCache.set(key, client)
  return client
}

function isEnvelope(value: unknown): value is Envelope {
  if (typeof value !== 'object' || value === null) return false
  if (!('ok' in value)) return false
  return (value as { ok: unknown }).ok === true || (value as { ok: unknown }).ok === false
}

/**
 * Maps a JSON envelope error to the frozen TypeScript error classes.
 */
export function reconstructEnvelopeError(error: EnvelopeErr['error']): Error {
  switch (error.kind) {
    case 'Paywall':
      return new PaywallError(error.message, error.gate as PaywallStructuredContent)
    case 'Api': {
      const init: { status?: number; code?: string } = {}
      if (typeof error.status === 'number') init.status = error.status
      if (typeof error.code === 'string') init.code = error.code
      return new SolvaPayError(error.message, init)
    }
    case 'Webhook':
    case 'Transport':
    default:
      return new SolvaPayError(error.message)
  }
}

/**
 * Parses a JSON envelope string and returns `value` or throws reconstructed errors.
 */
function unwrapEnvelope(envelopeJson: string): unknown {
  let envelope: unknown
  try {
    envelope = JSON.parse(envelopeJson) as unknown
  } catch {
    throw new SolvaPayError('SolvaPay WASM binding returned invalid JSON envelope')
  }

  if (!isEnvelope(envelope)) {
    throw new SolvaPayError('SolvaPay WASM binding returned malformed envelope')
  }

  if (envelope.ok) {
    return envelope.value
  }
  throw reconstructEnvelopeError(envelope.error)
}

/**
 * Calls a WASM `WasmClient` method (async) and reconstructs the envelope.
 *
 * Loads + instantiates the binding on first use. Success returns the envelope
 * `value` verbatim (no TS re-normalization); failure throws `SolvaPayError` /
 * `PaywallError`.
 */
export async function callWasm(
  fn: WasmClientMethod,
  argsJson: string,
  config: WasmClientConfig,
): Promise<unknown> {
  // An injected fake client (unit tests) needs no real module — skip the load
  // so dispatch tests stay hermetic under Node vitest.
  if (!isWasmClientOverrideActive()) {
    await loadWasmBinding()
  }
  const client = getWasmClient(config)
  const method = client[fn]
  if (typeof method !== 'function') {
    throw new SolvaPayError(`SolvaPay WASM client missing method: ${fn}`)
  }

  let envelopeJson: string
  try {
    envelopeJson = await method.call(client, argsJson)
  } catch (err) {
    if (err instanceof SolvaPayError || err instanceof PaywallError) {
      throw err
    }
    throw new SolvaPayError(err instanceof Error ? err.message : String(err))
  }

  return unwrapEnvelope(envelopeJson)
}

/**
 * Calls a sync top-level WASM pure-logic function and reconstructs the envelope.
 *
 * Requires a warmed module ({@link ensureWasmReadySync}). Success returns the
 * envelope `value` verbatim; failure throws `SolvaPayError` / `PaywallError`.
 */
export function callWasmSync(fn: WasmSyncMethod, argsJson: string): unknown {
  const binding = ensureWasmReadySync()
  const method = binding[fn]
  if (typeof method !== 'function') {
    throw new SolvaPayError(`SolvaPay WASM binding missing sync method: ${fn}`)
  }

  let envelopeJson: string
  try {
    envelopeJson = method(argsJson)
  } catch (err) {
    if (err instanceof SolvaPayError || err instanceof PaywallError) {
      throw err
    }
    throw new SolvaPayError(err instanceof Error ? err.message : String(err))
  }

  return unwrapEnvelope(envelopeJson)
}

/**
 * Ambient sync-dispatch registry symbol. Must match `SOLVAPAY_NATIVE_SYNC_API`
 * in `native-registry.ts` so `@solvapay/mcp-core` (resolved to the edge graph on
 * Deno) picks up whichever dispatch the active runtime published.
 */
const AMBIENT_SYNC_API = Symbol.for('solvapay.nativeSyncApi')

type AmbientSyncApi = {
  callNativeSync: (fn: WasmSyncMethod, argsJson: string) => unknown
}

/**
 * Publishes the WASM sync-dispatch API to the ambient registry — the edge
 * mirror of `native-registry.publishNativeSyncApi`. Lets `@solvapay/mcp-core`
 * pick up WASM dispatch without a hard `server → mcp-core` import cycle.
 */
export function publishWasmSyncApi(): void {
  const g = globalThis as typeof globalThis & {
    [AMBIENT_SYNC_API]?: AmbientSyncApi
  }
  g[AMBIENT_SYNC_API] = { callNativeSync: callWasmSync }
}

/**
 * Kicks off (idempotent) async warm-up so edge sync surfaces can init the WASM
 * module synchronously via {@link ensureWasmReadySync}. Fire-and-forget: never
 * rejects (errors surface later at call time, preserving the no-silent-fallback
 * edge contract).
 */
export function warmWasm(): void {
  void loadWasmBinding().catch(() => undefined)
}

/**
 * Verifies a webhook via `@solvapay/server-wasm`, rewrapping errors as
 * {@link SolvaPayError} while preserving snake_case `code` when present.
 */
export async function verifyWebhookWasm({
  body,
  signature,
  secret,
}: {
  body: string
  signature: string
  secret: string
}): Promise<WebhookEvent> {
  const binding = await loadWasmBinding()
  const nowUnixSecs = Math.floor(Date.now() / 1000)

  try {
    const json = binding.verifyWebhook(body, signature, secret, nowUnixSecs)
    try {
      return JSON.parse(json) as WebhookEvent
    } catch {
      throw new SolvaPayError('Invalid webhook payload from WASM binding', {
        code: 'internal_error',
      })
    }
  } catch (err) {
    if (err instanceof SolvaPayError) {
      throw err
    }
    const message = err instanceof Error ? err.message : String(err)
    const code = errorCodeFromUnknown(err)
    throw new SolvaPayError(message, code !== undefined ? { code } : {})
  }
}

function errorCodeFromUnknown(err: unknown): string | undefined {
  if (typeof err === 'object' && err !== null && 'code' in err) {
    const code = (err as { code?: unknown }).code
    if (typeof code === 'string') return code
  }
  return undefined
}
